const CLASSES: [&str; 4] = ["absent", "present_still", "present_moving", "active"];

/// Run MLP inference. Returns (class_index, confidence, class_name).
pub fn classify(features: &[f32; 31]) -> (usize, f32, &'static str) {
    // Normalize
    let mut x = [0.0f32; 31];
    for i in 0..31 {
        x[i] = (features[i] - NORM_MEAN[i]) / NORM_STD[i];
    }

    // Layer 0: ReLU(W0^T * x + b0)
    let mut h0 = [0.0f32; 64];
    for j in 0..64 {
        let mut s = B0[j];
        for i in 0..31 {
            s += x[i] * W0[i][j];
        }
        h0[j] = s.max(0.0);
    }

    // Layer 1: ReLU(W1^T * h0 + b1)
    let mut h1 = [0.0f32; 32];
    for j in 0..32 {
        let mut s = B1[j];
        for i in 0..64 {
            s += h0[i] * W1[i][j];
        }
        h1[j] = s.max(0.0);
    }

    // Layer 2: softmax(W2^T * h1 + b2)
    let mut logits = [0.0f32; 4];
    for j in 0..4 {
        let mut s = B2[j];
        for i in 0..32 {
            s += h1[i] * W2[i][j];
        }
        logits[j] = s;
    }

    // Softmax
    let max_l = logits.iter().cloned().fold(f32::NEG_INFINITY, f32::max);
    let exp_sum: f32 = logits.iter().map(|l| (l - max_l).exp()).sum();
    let probs: Vec<f32> = logits.iter().map(|l| (l - max_l).exp() / exp_sum).collect();

    let (best_idx, &best_prob) = probs.iter().enumerate()
        .max_by(|a, b| a.1.partial_cmp(b.1).unwrap())
        .unwrap();

    (best_idx, best_prob, CLASSES[best_idx])
}
